import { useEffect, useMemo, useState } from 'react';
import AdminMentorLayout from '../components/AdminMentorLayout.jsx';
import { ErrorState, LoadingState } from '../components/LoadingState.jsx';
import MetricCard from '../components/MetricCard.jsx';
import { adminMentorApi } from '../services/api.js';
import { formatCurrency, formatDateTime, formatPercent } from '../utils/formatters.js';

const rangeOptions = [
  { value: '7d', label: 'Last 7 days' },
  { value: '30d', label: 'Last 30 days' },
  { value: '90d', label: 'Last 90 days' },
];

function buildAnalyticsSummary(report) {
  if (!report) {
    return null;
  }

  // Tinh KPI tong hop tu report mock. Khi Backend reports hoan thien, frontend chi nen hien thi DTO da duoc backend tinh san.
  const revenueTotalFromSeries = report.revenue.series.reduce((total, item) => total + item.value, 0);
  const activeUserRate = Math.round((report.users.active / Math.max(report.users.total, 1)) * 100);
  const reviewCompletionRate = Math.round(
    (report.reviews.totalReviewed / Math.max(report.reviews.totalReviewed + report.reviews.pending, 1)) * 100,
  );

  return {
    revenueTotalFromSeries,
    activeUserRate,
    reviewCompletionRate,
    warningCount: report.warnings.length,
  };
}

export default function ReportsAnalyticsPage() {
  const [range, setRange] = useState('30d');
  const [report, setReport] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    let mounted = true;

    setLoading(true);
    adminMentorApi
      .getAdminReports({ range })
      .then((response) => {
        if (mounted) {
          setReport(response.data);
          setError('');
        }
      })
      .catch((requestError) => {
        if (mounted) {
          setError(requestError.message);
        }
      })
      .finally(() => {
        if (mounted) {
          setLoading(false);
        }
      });

    return () => {
      mounted = false;
    };
  }, [range]);

  const analytics = useMemo(() => buildAnalyticsSummary(report), [report]);
  const maxRevenue = useMemo(() => {
    if (!report) {
      return 1;
    }

    return Math.max(...report.revenue.series.map((item) => item.value), 1);
  }, [report]);

  return (
    <AdminMentorLayout
      area="admin"
      title="Reports & Analytics"
      subtitle="Bao cao read-only cho user, course, revenue va hieu suat mentor."
    >
      <div className="card admin-mentor-card mb-4">
        <div className="card-body">
          <div className="row g-3 align-items-end">
            <div className="col-12 col-md-4">
              <label className="form-label" htmlFor="admin-report-range">
                Date range
              </label>
              <select
                className="form-select"
                id="admin-report-range"
                onChange={(event) => setRange(event.target.value)}
                value={range}
              >
                {rangeOptions.map((option) => (
                  <option key={option.value} value={option.value}>
                    {option.label}
                  </option>
                ))}
              </select>
            </div>
            <div className="col-12 col-md-8">
              <div className="alert alert-info mb-0">
                Report UI dang dung mock Promise. Backend thật se validate query params va tra partial data
                warnings khi dependency timeout.
              </div>
            </div>
          </div>
        </div>
      </div>

      {loading ? <LoadingState message="Dang tai reports..." /> : null}
      {!loading && error ? <ErrorState message={error} /> : null}

      {!loading && report && analytics ? (
        <div className="d-grid gap-4">
          {report.warnings.length > 0 ? (
            <div className="alert alert-warning mb-0" role="alert">
              <strong>{analytics.warningCount} warning:</strong> {report.warnings[0].message}
            </div>
          ) : null}

          <div className="row g-3">
            <div className="col-12 col-md-6 col-xl-3">
              <MetricCard
                helper="Tong revenue SUCCESS"
                label="Revenue"
                tone="primary"
                value={formatCurrency(report.revenue.totalVnd)}
              />
            </div>
            <div className="col-12 col-md-6 col-xl-3">
              <MetricCard
                helper="Active users / total users"
                label="Active rate"
                tone="success"
                value={formatPercent(analytics.activeUserRate)}
              />
            </div>
            <div className="col-12 col-md-6 col-xl-3">
              <MetricCard
                helper="Course progress mock"
                label="Completion"
                tone="info"
                value={formatPercent(report.courses.completionRate)}
              />
            </div>
            <div className="col-12 col-md-6 col-xl-3">
              <MetricCard
                helper="Reviewed / all submissions"
                label="Review done"
                tone="warning"
                value={formatPercent(analytics.reviewCompletionRate)}
              />
            </div>
          </div>

          <div className="row g-4">
            <div className="col-12 col-xl-7">
              <div className="card admin-mentor-card h-100">
                <div className="card-header bg-white d-flex justify-content-between gap-3">
                  <div>
                    <h2 className="h5 mb-0">Revenue trend</h2>
                    <span className="small text-secondary">
                      Generated {formatDateTime(report.generatedAt)}
                    </span>
                  </div>
                  <span className="badge text-bg-light border">
                    Series total {formatCurrency(analytics.revenueTotalFromSeries)}
                  </span>
                </div>
                <div className="card-body">
                  <div className="d-grid gap-3">
                    {report.revenue.series.map((item) => (
                      <div key={item.label}>
                        <div className="d-flex justify-content-between mb-1">
                          <span>{item.label}</span>
                          <strong>{formatCurrency(item.value)}</strong>
                        </div>
                        <div className="progress admin-mentor-progress" role="progressbar">
                          <div
                            className="progress-bar"
                            style={{ width: `${Math.round((item.value / maxRevenue) * 100)}%` }}
                          />
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              </div>
            </div>

            <div className="col-12 col-xl-5">
              <div className="card admin-mentor-card h-100">
                <div className="card-header bg-white">
                  <h2 className="h5 mb-0">Review health</h2>
                </div>
                <div className="card-body">
                  <div className="row g-3 text-center">
                    <div className="col-6">
                      <div className="border rounded p-3">
                        <span className="small text-secondary d-block">PASS</span>
                        <strong className="h4">{report.reviews.pass}</strong>
                        <span className="small text-secondary d-block">{formatPercent(report.reviews.passRate)}</span>
                      </div>
                    </div>
                    <div className="col-6">
                      <div className="border rounded p-3">
                        <span className="small text-secondary d-block">FAIL</span>
                        <strong className="h4">{report.reviews.fail}</strong>
                        <span className="small text-secondary d-block">{formatPercent(report.reviews.failRate)}</span>
                      </div>
                    </div>
                    <div className="col-6">
                      <div className="border rounded p-3">
                        <span className="small text-secondary d-block">Pending</span>
                        <strong className="h4">{report.reviews.pending}</strong>
                      </div>
                    </div>
                    <div className="col-6">
                      <div className="border rounded p-3">
                        <span className="small text-secondary d-block">Reviewed</span>
                        <strong className="h4">{report.reviews.totalReviewed}</strong>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>

          <div className="row g-4">
            <div className="col-12 col-xl-6">
              <div className="card admin-mentor-card h-100">
                <div className="card-header bg-white">
                  <h2 className="h5 mb-0">Top courses</h2>
                </div>
                <div className="table-responsive">
                  <table className="table table-hover align-middle mb-0 admin-mentor-table">
                    <thead className="table-light">
                      <tr>
                        <th>Course</th>
                        <th>Learners</th>
                        <th>Completion</th>
                      </tr>
                    </thead>
                    <tbody>
                      {report.courses.topCourses.map((course) => (
                        <tr key={course.courseId}>
                          <td>{course.title}</td>
                          <td>{course.learners}</td>
                          <td>{formatPercent(course.completionRate)}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            </div>

            <div className="col-12 col-xl-6">
              <div className="card admin-mentor-card h-100">
                <div className="card-header bg-white">
                  <h2 className="h5 mb-0">Mentor performance</h2>
                </div>
                <div className="table-responsive">
                  <table className="table table-hover align-middle mb-0 admin-mentor-table">
                    <thead className="table-light">
                      <tr>
                        <th>Mentor</th>
                        <th>Reviewed</th>
                        <th>Pending</th>
                        <th>Avg hours</th>
                      </tr>
                    </thead>
                    <tbody>
                      {report.reviews.mentorPerformance.map((mentor) => (
                        <tr key={mentor.mentorId}>
                          <td>{mentor.mentorName}</td>
                          <td>{mentor.reviewed}</td>
                          <td>{mentor.pending}</td>
                          <td>{mentor.averageHoursToReview}h</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            </div>
          </div>
        </div>
      ) : null}
    </AdminMentorLayout>
  );
}
